import React, { useState } from 'react'

interface ParsedData {
  entities: string[]
  concepts: string[]
  confidence: number
}

interface KnowledgeParsingDemoProps {
  className?: string
}

const KnowledgeParsingDemo: React.FC<KnowledgeParsingDemoProps> = ({ className }) => {
  const [inputText, setInputText] = useState('')
  const [parsedData, setParsedData] = useState<ParsedData | null>(null)
  const [isLoading, setIsLoading] = useState(false)

  const handleParse = async () => {
    if (!inputText.trim()) {
      return
    }
    
    setIsLoading(true)
    // Simulate parsing delay
    await new Promise(resolve => setTimeout(resolve, 1000))
    
    // Mock parsed data
    setParsedData({
      entities: ['anxiety', 'therapy', 'cognitive'],
      concepts: ['cognitive behavioral therapy', 'exposure therapy'],
      confidence: 0.85
    })
    setIsLoading(false)
  }

  return (
    <div className={`knowledge-parsing-demo ${className || ''}`}>
      <h2>Knowledge Parsing Demo</h2>
      <div className="demo-interface">
        <div className="input-section">
          <textarea
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            placeholder="Enter psychological text to parse..."
            rows={4}
            cols={50}
          />
          <button onClick={handleParse} disabled={isLoading}>
            {isLoading ? 'Parsing...' : 'Parse Knowledge'}
          </button>
        </div>
        
        {parsedData && (
          <div className="results-section">
            <h3>Parsed Results:</h3>
            <div className="parsed-entities">
              <h4>Entities:</h4>
              <ul>
                {parsedData.entities.map((entity: string) => (
                  <li key={entity}>{entity}</li>
                ))}
              </ul>
            </div>
            <div className="parsed-concepts">
              <h4>Concepts:</h4>
              <ul>
                {parsedData.concepts.map((concept: string) => (
                  <li key={concept}>{concept}</li>
                ))}
              </ul>
            </div>
            <div className="confidence">
              <h4>Confidence: {(parsedData.confidence * 100).toFixed(1)}%</h4>
            </div>
          </div>
        )}
      </div>
    </div>
  )
}

export default KnowledgeParsingDemo
